import React, { useState } from 'react';
import './App.css';
import { HashRouter as Router, Route, Routes, Link , } from 'react-router-dom';
import Fun from './Fun';
import Home from './Home';
import { IconButton, Drawer, List, ListItem, ListItemText } from '@mui/material';
import MenuIcon from '@mui/icons-material/Menu';
import Switch from '@mui/material/Switch';
import { ThemeProvider, createTheme } from '@mui/material/styles';

function App() {
  const lightTheme = createTheme({
    palette: {
      type: 'light',
      primary: {
        main: '#2196F3',
      },
      secondary: {
        main: '#1565C0',
      },
    },
  });

  const darkTheme = createTheme({
    palette: {
      type: 'dark',
      primary: {
        main: '#2196F3',
      },
      secondary: {
        main: '#1565C0',
      },
    },
  });

  const [menuOpen, setMenuOpen] = useState(false);
  const [selectedTheme, setSelectedTheme] = useState('light');

  const toggleMenu = () => {
    setMenuOpen(!menuOpen);
  };

  const handleThemeChange = (theme) => {
    setSelectedTheme(theme);
  };

  const scrollToTop = () => {
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
  };

  return (
    <ThemeProvider theme={selectedTheme === 'light' ? lightTheme : darkTheme}>
      <Router>
        <div className={`App ${menuOpen ? 'open' : ''}`}>
          <div className="menu">
            <IconButton edge="start" color="inherit" aria-label="menu" onClick={toggleMenu}>
              <MenuIcon />
            </IconButton>
            <Drawer anchor="left" open={menuOpen} onClose={toggleMenu}>
              <List>
                <ListItem button component={Link} to="/" onClick={toggleMenu}>
                  <ListItemText primary="Home" />
                </ListItem>
                <ListItem button component={Link} to="/fun" onClick={toggleMenu}>
                  <ListItemText primary="Fun" />
                </ListItem>
                <ListItem>
                  <ListItemText primary="Theme" />
                  <Switch
                    color="primary"
                    checked={selectedTheme === 'dark'}
                    onChange={() => handleThemeChange(selectedTheme === 'light' ? 'dark' : 'light')}
                  />
                </ListItem>
              </List>
            </Drawer>
          </div>
          <div className="scroll-to-top" onClick={scrollToTop}>Top</div>

          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/fun" element={<Fun />} />
          </Routes>
        </div>
      </Router>
    </ThemeProvider>
  );
}

export default App;